// Fetch pay-as-you-go account balances. One output item per provider.
// Keys + tuning come from n8n env (see roles/n8n/templates/n8n.env.j2).
const EUR = parseFloat($env.EUR_PER_USD || '0.92');
const MIN = parseFloat($env.CREDIT_ALERT_MIN_USD || '5');
const toEur = (usd) => Math.round(usd * EUR * 100) / 100;
const round2 = (n) => Math.round(n * 100) / 100;

async function probe(provider, fn) {
  try {
    const usd = await fn();
    if (usd === null || usd === undefined || isNaN(usd)) {
      return { provider, ok: false, error: 'no balance value in API response' };
    }
    return {
      provider,
      ok: true,
      balanceUsd: round2(usd),
      balanceEur: toEur(usd),
      thresholdUsd: MIN,
      lowBalance: usd < MIN
    };
  } catch (e) {
    return { provider, ok: false, error: e.message || String(e) };
  }
}

const results = [];

// OpenRouter — remaining credit = total_credits - total_usage (USD)
results.push(await probe('openrouter', async () => {
  const key = $env.OPENROUTER_API_KEY;
  if (!key) throw new Error('OPENROUTER_API_KEY not set');
  const r = await fetch('https://openrouter.ai/api/v1/credits', {
    headers: { Authorization: 'Bearer ' + key }
  });
  if (!r.ok) throw new Error('HTTP ' + r.status);
  const j = await r.json();
  const d = j.data || {};
  return (d.total_credits || 0) - (d.total_usage || 0);
}));

// Runpod — GraphQL clientBalance (USD)
results.push(await probe('runpod', async () => {
  const key = $env.RUNPOD_API_KEY;
  if (!key) throw new Error('RUNPOD_API_KEY not set');
  const r = await fetch('https://api.runpod.io/graphql', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + key },
    body: JSON.stringify({ query: '{ myself { clientBalance } }' })
  });
  if (!r.ok) throw new Error('HTTP ' + r.status);
  const j = await r.json();
  if (j.errors && j.errors.length) throw new Error(j.errors[0].message);
  return j.data && j.data.myself ? j.data.myself.clientBalance : null;
}));

// fal.ai — best-effort (billing API path overridable via FAL_BALANCE_URL).
// On failure the alert branch tells you to enter the credit manually.
results.push(await probe('fal.ai', async () => {
  const key = $env.FAL_KEY;
  if (!key) throw new Error('FAL_KEY not set');
  const url = $env.FAL_BALANCE_URL || 'https://rest.alpha.fal.ai/billing/user_spend';
  const r = await fetch(url, { headers: { Authorization: 'Key ' + key } });
  if (!r.ok) throw new Error('HTTP ' + r.status + ' (override FAL_BALANCE_URL or enter fal credit manually)');
  const j = await r.json();
  const bal = j.balance ?? j.credit ?? j.remaining ?? j.available ?? null;
  if (bal === null) throw new Error('balance field not found in fal response');
  return bal;
}));

return results.map((json) => ({ json }));

// Aggregate all provider results (runs once) → build a single alert if any
// balance is below threshold or any fetch failed.
const items = $input.all().map((i) => i.json);
const low = items.filter((i) => i.ok && i.lowBalance);
const failed = items.filter((i) => !i.ok);

if (low.length === 0 && failed.length === 0) {
  return [{ json: { alert: false } }];
}

const lines = ['\uD83D\uDCB3 <b>Suivi cr\u00e9dits \u2014 alerte soldes</b>', ''];
for (const i of items) {
  if (i.ok) {
    const e = i.lowBalance ? '\uD83D\uDD34' : '\u2705';
    lines.push(`${e} <b>${i.provider}</b> : $${i.balanceUsd} (~${i.balanceEur}\u20ac)` + (i.lowBalance ? ` \u2014 sous le seuil $${i.thresholdUsd}` : ''));
  } else {
    lines.push(`\u26A0\uFE0F <b>${i.provider}</b> : \u00e9chec r\u00e9cup\u00e9ration \u2014 ${i.error}`);
  }
}
if (failed.some((f) => f.provider === 'fal.ai')) {
  lines.push('');
  lines.push('\u2139\uFE0F fal.ai : si l\'API solde est indisponible, corrige FAL_BALANCE_URL ou saisis le cr\u00e9dit \u00e0 la main via POST /api/v2/costs/entries (provider="fal.ai", category="credit").');
}

return [{ json: { alert: true, message: lines.join('\n') } }];
